<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  :root {
    --ubuntu-orange: #E95420;
    --ubuntu-purple: #772953;
    --panel-bg: rgba(20, 20, 24, 0.92);
    --window-bg: #2c2c34;
    --window-header: #3a3a44;
    --text: #f0f0f0;
    --text-dim: #a8a8b0;
    --accent: #E95420;
  }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    color: var(--text);
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    width: 100vw;
    height: 100vh;
    background:
      radial-gradient(ellipse at 20% 15%, rgba(233, 84, 32, 0.30) 0%, transparent 55%),
      radial-gradient(ellipse at 80% 85%, rgba(119, 41, 83, 0.55) 0%, transparent 60%),
      linear-gradient(135deg, #3b1b33 0%, #2a1229 40%, #1a0d1e 100%);
    overflow: hidden;
  }
  #desktop::before {
    content: "";
    position: absolute;
    inset: 0;
    background-image: radial-gradient(rgba(255,255,255,0.045) 1px, transparent 1px);
    background-size: 26px 26px;
    pointer-events: none;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 30px;
    background: var(--panel-bg);
    backdrop-filter: blur(8px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 5000;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #topbar .tb-left { color: var(--text-dim); font-weight: 500; }
  #topbar .tb-center { font-weight: 500; }
  #topbar .tb-right { display: flex; gap: 10px; color: var(--text-dim); }

  /* ---------- Dock / Taskbar ---------- */
  #taskbar {
    position: absolute;
    left: 0;
    top: 30px;
    bottom: 0;
    width: 68px;
    background: var(--panel-bg);
    backdrop-filter: blur(8px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 10px;
    z-index: 4000;
    border-right: 1px solid rgba(255,255,255,0.06);
  }
  .launcher {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    background: rgba(255,255,255,0.06);
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    color: var(--text);
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .launcher:hover { background: rgba(255,255,255,0.16); }
  .launcher:active { transform: scale(0.93); }
  .launcher .icon { font-size: 24px; line-height: 1; }
  .launcher .lbl { font-size: 9px; color: var(--text-dim); }
  .launcher.running::after {
    content: "";
    position: absolute;
    left: -8px;
    top: 50%;
    transform: translateY(-50%);
    width: 4px;
    height: 22px;
    border-radius: 2px;
    background: var(--ubuntu-orange);
  }

  /* ---------- Windows ---------- */
  .app-window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 560px;
    height: 400px;
    background: var(--window-bg);
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55), 0 0 0 1px rgba(255,255,255,0.08);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .app-window.hidden { display: none; }
  .win-titlebar {
    height: 36px;
    flex: 0 0 36px;
    background: var(--window-header);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    border-bottom: 1px solid rgba(0,0,0,0.35);
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title {
    flex: 1;
    text-align: center;
    font-size: 13px;
    font-weight: 500;
    pointer-events: none;
  }
  .win-btns { display: flex; gap: 8px; }
  .win-close {
    width: 22px;
    height: 22px;
    border: none;
    border-radius: 50%;
    background: var(--ubuntu-orange);
    color: #fff;
    font-size: 12px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .win-close:hover { background: #ff6a35; }
  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    overflow: hidden;
  }

  /* ---------- Files app ---------- */
  #files-window .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: rgba(0,0,0,0.18);
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #files-up {
    border: none;
    background: rgba(255,255,255,0.1);
    color: var(--text);
    border-radius: 6px;
    padding: 5px 12px;
    font-size: 14px;
    cursor: pointer;
  }
  #files-up:hover { background: rgba(255,255,255,0.2); }
  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.3);
    border-radius: 6px;
    padding: 6px 10px;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 13px;
    color: var(--text);
    white-space: nowrap;
    overflow: auto hidden;
  }
  #files-list {
    flex: 1;
    overflow: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    font-size: 12px;
    word-break: break-all;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item .fs-icon { font-size: 30px; line-height: 1; pointer-events: none; }
  .fs-empty { color: var(--text-dim); font-size: 13px; padding: 16px; grid-column: 1 / -1; }

  /* ---------- Notepad ---------- */
  #notepad-window .np-toolbar {
    display: flex;
    align-items: stretch;
    background: rgba(0,0,0,0.18);
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }
  #tabs {
    display: flex;
    flex: 1;
    overflow-x: auto;
    overflow-y: hidden;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 8px 12px;
    font-size: 12px;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.06);
    color: var(--text-dim);
    white-space: nowrap;
    max-width: 160px;
  }
  .tab:hover { background: rgba(255,255,255,0.06); }
  .tab.active {
    background: var(--window-bg);
    color: var(--text);
    box-shadow: inset 0 -2px 0 var(--ubuntu-orange);
  }
  .tab .tab-x {
    border: none;
    background: transparent;
    color: inherit;
    cursor: pointer;
    font-size: 11px;
    padding: 0 2px;
    border-radius: 3px;
  }
  .tab .tab-x:hover { background: rgba(255,255,255,0.18); }
  #new-tab {
    border: none;
    background: transparent;
    color: var(--text);
    font-size: 17px;
    padding: 0 14px;
    cursor: pointer;
  }
  #new-tab:hover { background: rgba(255,255,255,0.1); }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1f1f26;
    color: var(--text);
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px;
    user-select: text;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span class="tb-left">Activities</span>
    <span class="tb-center" id="clock">--:--</span>
    <span class="tb-right"><span>&#9679;</span><span>&#9650;</span><span>&#128267;</span></span>
  </div>

  <div id="taskbar">
    <button id="open-files" class="launcher" title="Files">
      <span class="icon">&#128193;</span><span class="lbl">Files</span>
    </button>
    <button id="open-notepad" class="launcher" title="Notepad">
      <span class="icon">&#128221;</span><span class="lbl">Notepad</span>
    </button>
  </div>

  <!-- Files window -->
  <div id="files-window" class="app-window hidden" style="left: 140px; top: 90px; width: 620px; height: 430px;">
    <div class="win-titlebar">
      <div class="win-btns"><button class="win-close" title="Close">&#10005;</button></div>
      <div class="win-title">Files</div>
      <div class="win-btns" style="visibility:hidden;"><button class="win-close">&#10005;</button></div>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up" title="Up one level">&#8593;</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="app-window hidden" style="left: 260px; top: 140px; width: 580px; height: 410px;">
    <div class="win-titlebar">
      <div class="win-btns"><button class="win-close" title="Close">&#10005;</button></div>
      <div class="win-title">Notepad</div>
      <div class="win-btns" style="visibility:hidden;"><button class="win-close">&#10005;</button></div>
    </div>
    <div class="win-body">
      <div class="np-toolbar">
        <div id="tabs"></div>
        <button id="new-tab" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ================= Clock ================= */
  const clock = document.getElementById("clock");
  function tick() {
    const d = new Date();
    clock.textContent = d.toLocaleDateString(undefined, { month: "short", day: "numeric" }) +
      "  " + d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit" });
  }
  tick();
  setInterval(tick, 10000);

  /* ================= Window manager ================= */
  let zTop = 100;
  function bringToFront(win) { win.style.zIndex = ++zTop; }

  function setupWindow(winId, launcherId) {
    const win = document.getElementById(winId);
    const launcher = document.getElementById(launcherId);

    launcher.addEventListener("click", function () {
      win.classList.remove("hidden");
      launcher.classList.add("running");
      bringToFront(win);
    });

    win.querySelectorAll(".win-close").forEach(function (btn) {
      btn.addEventListener("click", function () {
        win.classList.add("hidden");
        launcher.classList.remove("running");
      });
    });

    win.addEventListener("mousedown", function () { bringToFront(win); });

    // Dragging via titlebar
    const bar = win.querySelector(".win-titlebar");
    bar.addEventListener("mousedown", function (e) {
      if (e.target.closest(".win-close")) return;
      e.preventDefault();
      bringToFront(win);
      const startX = e.clientX, startY = e.clientY;
      const startLeft = win.offsetLeft, startTop = win.offsetTop;
      function onMove(ev) {
        let nl = startLeft + (ev.clientX - startX);
        let nt = startTop + (ev.clientY - startY);
        nl = Math.max(0, Math.min(nl, window.innerWidth - 80));
        nt = Math.max(30, Math.min(nt, window.innerHeight - 40));
        win.style.left = nl + "px";
        win.style.top = nt + "px";
      }
      function onUp() {
        document.removeEventListener("mousemove", onMove);
        document.removeEventListener("mouseup", onUp);
      }
      document.addEventListener("mousemove", onMove);
      document.addEventListener("mouseup", onUp);
    });
  }

  setupWindow("files-window", "open-files");
  setupWindow("notepad-window", "open-notepad");

  /* ================= Files app ================= */
  // Fake Linux filesystem: object = directory, string = file contents (unused, just marks a file)
  const FS = {
    bin: { bash: "", cat: "", cp: "", ls: "", mkdir: "", mv: "", rm: "", sh: "", grep: "" },
    boot: { "vmlinuz-6.8.0-generic": "", "initrd.img-6.8.0-generic": "", grub: { "grub.cfg": "" } },
    dev: { null: "", zero: "", random: "", sda: "", tty0: "" },
    etc: {
      hostname: "", hosts: "", fstab: "", passwd: "", shadow: "", "os-release": "",
      apt: { "sources.list": "" },
      ssh: { sshd_config: "" },
      systemd: { "system.conf": "" }
    },
    home: {
      user: {
        Documents: {
          "notes.txt": "",
          "todo.md": "",
          Projects: { "readme.md": "", "ideas.txt": "" }
        },
        Downloads: { "ubuntu-24.04.iso": "", "wallpaper.png": "" },
        Pictures: {
          "screenshot.png": "", "avatar.jpg": "",
          Vacation: { "beach.jpg": "", "sunset.jpg": "" }
        },
        Music: {},
        Videos: {},
        ".bashrc": "",
        ".profile": ""
      }
    },
    lib: { systemd: {}, firmware: {} },
    opt: {},
    proc: { cpuinfo: "", meminfo: "", uptime: "" },
    root: { ".bashrc": "" },
    sbin: { init: "", reboot: "", shutdown: "" },
    tmp: {},
    usr: {
      bin: { python3: "", vim: "", nano: "", gcc: "", curl: "" },
      lib: {},
      local: { bin: {}, share: {} },
      share: { doc: {}, man: {}, icons: {} }
    },
    var: {
      log: { syslog: "", "auth.log": "", "dpkg.log": "" },
      cache: { apt: {} },
      tmp: {},
      www: { html: { "index.html": "" } }
    }
  };

  let cwd = []; // array of path segments; [] = root
  const filesPath = document.getElementById("files-path");
  const filesList = document.getElementById("files-list");
  const filesUp = document.getElementById("files-up");

  function getDir(segments) {
    let node = FS;
    for (const seg of segments) {
      if (node && typeof node === "object" && typeof node[seg] === "object") {
        node = node[seg];
      } else {
        return null;
      }
    }
    return node;
  }

  function renderFiles() {
    filesPath.textContent = "/" + cwd.join("/");
    filesList.innerHTML = "";
    const dir = getDir(cwd) || FS;
    const names = Object.keys(dir).sort(function (a, b) {
      const ad = typeof dir[a] === "object", bd = typeof dir[b] === "object";
      if (ad !== bd) return ad ? -1 : 1; // folders first
      return a.localeCompare(b);
    });
    if (names.length === 0) {
      const empty = document.createElement("div");
      empty.className = "fs-empty";
      empty.textContent = "This folder is empty";
      filesList.appendChild(empty);
      return;
    }
    for (const name of names) {
      const isDir = typeof dir[name] === "object";
      const el = document.createElement("div");
      el.className = "fs-item";
      el.dataset.name = name;
      el.dataset.dir = isDir ? "1" : "0";
      el.title = name;

      const icon = document.createElement("span");
      icon.className = "fs-icon";
      icon.textContent = isDir ? "\u{1F4C1}" : "\u{1F4C4}";
      el.appendChild(icon);
      el.appendChild(document.createTextNode(name));

      if (isDir) {
        el.addEventListener("dblclick", function () {
          cwd.push(name);
          renderFiles();
        });
      }
      filesList.appendChild(el);
    }
  }

  filesUp.addEventListener("click", function () {
    if (cwd.length > 0) {
      cwd.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ================= Notepad app ================= */
  const STORE_KEY = "ubuntu-notepad-tabs-v1";
  const tabsEl = document.getElementById("tabs");
  const newTabBtn = document.getElementById("new-tab");
  const editor = document.getElementById("editor");

  let state = loadState();

  function loadState() {
    try {
      const raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          if (typeof parsed.active !== "number" ||
              parsed.active < 0 || parsed.active >= parsed.tabs.length) {
            parsed.active = 0;
          }
          parsed.tabs = parsed.tabs.map(function (t, i) {
            return {
              title: (t && typeof t.title === "string" && t.title) || ("Untitled " + (i + 1)),
              content: (t && typeof t.content === "string") ? t.content : ""
            };
          });
          return parsed;
        }
      }
    } catch (e) { /* corrupted storage — start fresh */ }
    return { tabs: [{ title: "Untitled 1", content: "" }], active: 0 };
  }

  function saveState() {
    try { localStorage.setItem(STORE_KEY, JSON.stringify(state)); } catch (e) {}
  }

  function nextUntitledName() {
    let n = 1;
    const names = new Set(state.tabs.map(function (t) { return t.title; }));
    while (names.has("Untitled " + n)) n++;
    return "Untitled " + n;
  }

  function renderTabs() {
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (tab, i) {
      const el = document.createElement("div");
      el.className = "tab" + (i === state.active ? " active" : "");

      const label = document.createElement("span");
      label.textContent = tab.title;
      el.appendChild(label);

      if (state.tabs.length > 1) {
        const x = document.createElement("button");
        x.className = "tab-x";
        x.textContent = "\u00D7";
        x.title = "Close tab";
        x.addEventListener("click", function (e) {
          e.stopPropagation();
          state.tabs.splice(i, 1);
          if (state.active >= state.tabs.length) state.active = state.tabs.length - 1;
          else if (state.active > i) state.active--;
          saveState();
          renderTabs();
          renderEditor();
        });
        el.appendChild(x);
      }

      el.addEventListener("click", function () {
        state.active = i;
        saveState();
        renderTabs();
        renderEditor();
      });

      tabsEl.appendChild(el);
    });
  }

  function renderEditor() {
    editor.value = state.tabs[state.active].content;
  }

  newTabBtn.addEventListener("click", function () {
    state.tabs.push({ title: nextUntitledName(), content: "" });
    state.active = state.tabs.length - 1;
    saveState();
    renderTabs();
    renderEditor();
    editor.focus();
  });

  editor.addEventListener("input", function () {
    state.tabs[state.active].content = editor.value;
    saveState();
  });

  renderTabs();
  renderEditor();
})();
</script>
</body>
</html>
